INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-06440', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '我路經一個小店，店主人對我說，他養的八哥會說五句話：「對不起」，「謝謝 你」，「你好嗎？」「早安」，「再見」。他見過更聰明的八哥。我安慰他說： 「會說這五句話的八哥已經很了不起了，許多很會說話的人，連這五句話都說不完 全哩！」以下說明，何者最接近文中意涵？', '["顯示八哥慧黠", "顯示作者體諒", "諷刺主人虛偽", "諷刺人們無禮"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "bdb2fa9e8569", "answer_pdf_sha1": "4961f10a12fc", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06441', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「少年時，我曾多次從蛇口中救出那些哀鳴的青蛙，並以此自認為做到了日行一 善。及長，我逐漸明瞭大自然的生態法則，許多生命的維持須靠許多生命的結束來 達到，對一種生物的仁慈就是對他種生物的殘酷。」下列敘述何者較接近上文意 旨？', '["肯定適者生存法則", "提倡天人合一觀念", "批判自我中心觀念", "反對干預自然法則 「吾友嘗告我以其尊翁晚年，一生文稿，堆積生蠹，家人乘其外出時付之一炬。 先生返而見之，嘆劫數不已。我雅不願我之手稿遭同樣命運，故乘今日尚勉強能工作 之時，將其整理，選出若干篇，依其性質，分別彙輯，亦敝帚自珍耳。」 請依上文回答第11題至第12題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "bdb2fa9e8569", "answer_pdf_sha1": "4961f10a12fc", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06442', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列敘述，何者接近文中「我」所敘之事實？', '["「我」的父親文稿被燒", "「我」的朋友文稿被毀", "「我」的手稿需要清掃存放", "「我」的文稿需要編輯傳世"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "bdb2fa9e8569", "answer_pdf_sha1": "4961f10a12fc", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06443', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列敘述，何者最接近文中心情？', '["惕勉", "追憶", "傷逝", "奮勇 「寒蟬淒切，對長亭晚，驟雨初歇。都門帳飲無緒，留戀處、蘭舟催發。執手相 看淚眼，竟無語凝噎。念去去、千里煙波，暮靄沉沉楚天闊。  多情自古傷離別，更那 堪、冷落清秋節！今宵酒醒何處？楊柳岸、曉風殘月。此去經年，應是良辰好景虛設。 便縱有、千種風情，更與何人說？」（柳永〈雨霖鈴〉） 請依上文回答第13題至第15題"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "bdb2fa9e8569", "answer_pdf_sha1": "4961f10a12fc", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06444', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '本詞旨在抒發：', '["物在人亡的傷感", "臨別不捨的心緒", "懷才不遇的憤悶", "故地重遊的懷想"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "bdb2fa9e8569", "answer_pdf_sha1": "4961f10a12fc", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06445', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列選項中，那一個不是作者寫作本詞時當下的實景？', '["寒蟬淒切", "驟雨初歇", "蘭舟催發", "曉風殘月"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "bdb2fa9e8569", "answer_pdf_sha1": "4961f10a12fc", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06446', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「此去經年，應是良辰好景虛設。便縱有、千種風情，更與何人說」，意境與下列 那一個選項最為接近？', '["獨自莫憑欄，無限江山，別時容易見時難", "斷腸點點飛紅，都無人管，倩誰喚、流鶯聲住", "錦瑟華年誰與度？月橋花院，瑣窗朱戶，只有春知處", "花前失卻游春侶，獨自尋芳。滿目淒涼，縱有笙歌亦斷腸 「吾嘗終日而思矣，不如須臾之所學也。吾嘗跂而望矣，不如登高之博見也。登高 而招，臂非加長也，而見者遠；順風而呼，聲非加疾也，而聞者彰。假輿馬者，非利足 也，而致千里；假舟楫者，非能水也，而絕江河。」(《荀子．勸學》) 請依上文回答第16題至第17題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "bdb2fa9e8569", "answer_pdf_sha1": "4961f10a12fc", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06447', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '文中「吾嘗跂而望矣」，意為：', '["登上斜坡向遠方看去", "迷失歧途而難以望遠", "以正確角度極目望遠", "提起腳跟向遠方看去"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "bdb2fa9e8569", "answer_pdf_sha1": "4961f10a12fc", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06448', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列選項中何者與上文旨意相符？', '["君子之道，費而隱", "君子之道，闇然而日章", "君子生非異也，善假於物也", "君子遠庖廚，凡有血氣之類，弗身踐也"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "bdb2fa9e8569", "answer_pdf_sha1": "4961f10a12fc", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06449', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '莊周家貧，故往貸粟於監河侯，監河侯曰：「諾！我將得邑金，將貸子三百金，可 乎？」莊周忿然作色曰：「周昨來，有中道而呼者，周顧視車轍中，有鮒魚焉。周 問之曰：『鮒魚來，子何為者邪？』對曰：『我，東海之波臣也，君豈有斗升之水 而活我哉？』周曰：『諾！我且南遊吳越之王，激西江之水而迎子，可乎？』鮒魚 忿然作色曰：『吾失我常與，我無所處，吾得斗升之水，然活耳，君乃言此，曾不 如早索我於枯魚之肆。』」（《莊子．外物》）此故事可用下列那一句話來表達它 的意旨？', '["冷暖自知", "光說不練", "欲速則不達", "遠水救不了近火"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "bdb2fa9e8569", "answer_pdf_sha1": "4961f10a12fc", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
